from collections import deque
def components(coord_list):
    unvisited=set(coord_list)
    comps=[]
    while unvisited:
        comp=[]
        q=[unvisited.pop()]
        while q:
            r,c=q.pop()
            comp.append((r,c))
            for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                nr,nc = r+dr, c+dc
                if (nr,nc) in unvisited:
                    unvisited.remove((nr,nc))
                    q.append((nr,nc))
        comps.append(comp)
    return comps
